import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        char[] buffer = new char[10];

        // Copy only up to the length of the buffer, avoiding buffer overflow
        for (int i = 0; i < Math.min(name.length(), buffer.length); i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Buffer overflow prevented. Name: " + new String(buffer));
    }
}

